import{_ as t,c as l,o as i,a5 as e,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.16：稳定性与体验优化","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.16.md","filePath":"changelog/v1.1.16.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.16.md"};function d(n,r,h,s,c,p){return i(),l("div",null,[...r[0]||(r[0]=[e('<h1 id="v1-1-16-稳定性与体验优化" tabindex="-1">v1.1.16：稳定性与体验优化 <a class="header-anchor" href="#v1-1-16-稳定性与体验优化" aria-label="Permalink to “v1.1.16：稳定性与体验优化”">​</a></h1><p><strong>发布日期</strong>：2026年1月13日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新<strong>改进了编辑工具的反馈机制</strong>，让你更清楚地知道代码修改是否成功，同时修复了多个影响日常使用的问题。</p><hr><h2 id="改进-编辑工具反馈优化" tabindex="-1">改进：编辑工具反馈优化 <a class="header-anchor" href="#改进-编辑工具反馈优化" aria-label="Permalink to “改进：编辑工具反馈优化”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>编辑和写入工具现在会给出更明确的反馈，让你清楚知道：</p><ul><li>修改是否成功应用</li><li>如果失败，具体原因是什么</li></ul><p><strong>之前</strong>：有时候不确定代码修改是否真的生效了。</p><p><strong>现在</strong>：每次修改都会有明确的成功/失败提示。</p><hr><h2 id="改进-环境文件读取权限" tabindex="-1">改进：环境文件读取权限 <a class="header-anchor" href="#改进-环境文件读取权限" aria-label="Permalink to “改进：环境文件读取权限”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>读取 <code>.env</code> 等环境配置文件时，现在会<strong>询问用户是否允许</strong>，而不是直接阻止。</p><p><strong>之前</strong>：尝试读取环境文件可能被静默阻止。</p><p><strong>现在</strong>：OpenCode 会弹出权限确认，你可以选择是否允许。</p><p>这让你在需要帮助配置环境变量时更加灵活，同时保持了安全性。</p><hr><h2 id="新功能-cli-调试工具调用" tabindex="-1">新功能：CLI 调试工具调用 <a class="header-anchor" href="#新功能-cli-调试工具调用" aria-label="Permalink to “新功能：CLI 调试工具调用”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在可以直接在命令行调试工具调用，方便开发和测试。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3>',24),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode debug tool <工具名称>")])],-1),e('<p>这对开发自定义工具或排查问题非常有帮助。</p><hr><h2 id="改进-mcp-服务器配置" tabindex="-1">改进：MCP 服务器配置 <a class="header-anchor" href="#改进-mcp-服务器配置" aria-label="Permalink to “改进：MCP 服务器配置”">​</a></h2><h3 id="修复-mcp-add-命令" tabindex="-1">修复：<code>mcp add</code> 命令 <a class="header-anchor" href="#修复-mcp-add-命令" aria-label="Permalink to “修复：mcp add 命令”">​</a></h3><p><strong>之前的问题</strong>：使用 <code>mcp add</code> 添加 MCP 服务器时，配置没有真正写入 OpenCode 配置文件。</p><p><strong>现在</strong>：配置会正确保存，添加的 MCP 服务器下次启动时自动可用。</p><hr><h2 id="改进-子代理权限" tabindex="-1">改进：子代理权限 <a class="header-anchor" href="#改进-子代理权限" aria-label="Permalink to “改进：子代理权限”">​</a></h2><h3 id="这次更新了什么-3" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-3" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>嵌套子代理现在会正确继承父代理的任务权限设置。</p><p><strong>之前</strong>：有时候子代理的权限设置不生效。</p><p><strong>现在</strong>：权限设置在整个代理调用链中正确传递。</p><hr><h2 id="桌面版更新" tabindex="-1">桌面版更新 <a class="header-anchor" href="#桌面版更新" aria-label="Permalink to “桌面版更新”">​</a></h2><ul><li><strong>本地服务器密码</strong>：桌面应用启动的本地服务器现在支持密码保护</li><li><strong>终端编号优化</strong>：多终端场景下的编号更加智能</li><li><strong>Windows 修复</strong>：修复 Windows 下 Tauri CLI 启动参数问题</li></ul><hr><h2 id="其他修复" tabindex="-1">其他修复 <a class="header-anchor" href="#其他修复" aria-label="Permalink to “其他修复”">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>修复</th></tr></thead><tbody><tr><td>切换会话时误提交</td><td>✅ 已修复</td></tr><tr><td>控制台显示 <code>[object Object]</code> 错误</td><td>✅ 已修复</td></tr><tr><td>Cloudflare 提供商的 token 限制错误</td><td>✅ 已修复</td></tr><tr><td>Bedrock 的 Anthropic 模型推理配置</td><td>✅ 已修复</td></tr></tbody></table><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>用过 <code>mcp add</code> 但服务器没生效</td><td>✅ 升级</td></tr><tr><td>使用 Cloudflare 提供商</td><td>✅ 升级</td></tr><tr><td>使用 AWS Bedrock + Claude</td><td>✅ 升级</td></tr><tr><td>遇到过编辑后不确定是否成功</td><td>✅ 升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',22),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),e('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>处理更新 OpenCode 配置 schema 时的写入错误 (@ShoeBoom)</li><li>确保 zai 模型禁用 clear_thinking</li><li>改进编辑和写入工具反馈，避免对修改结果产生困惑</li><li>防止控制台输出 [object Object] 错误 (@lengmodkx)</li><li>嵌套子代理正确继承父代理任务权限 (@malhashemi)</li><li>修复 Cloudflare 提供商的 max completion tokens 错误 (@roerohan)</li><li>Bedrock 的 Anthropic 模型使用 reasoningConfig (@Adam8234)</li><li>在会话元数据中存储 API URL (@jkoelker)</li><li>添加 nova-2 到区域前缀模型</li><li>环境文件读取改为询问用户权限</li><li>使用 Biome check 替代 format 以包含导入排序 (@kynnyhsap)</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>CLI 支持直接调试工具调用 (@Eric-Guo)</li><li>切换会话时不再提交 prompt (@LeonMueller-OneAndOnly)</li><li>设置 API key 时 await auth.set 防止竞态条件 (@darshkpatel)</li><li><code>mcp add</code> 命令现在正确修改 OpenCode 配置 (@paoloricciuti)</li></ul><h3 id="desktop-桌面版" tabindex="-1">Desktop（桌面版） <a class="header-anchor" href="#desktop-桌面版" aria-label="Permalink to “Desktop（桌面版）”">​</a></h3><ul><li>桌面应用启动本地服务器时带密码 (@Brendonovich)</li><li>修复 Windows Tauri CLI 启动缺少参数 (@pschiel)</li><li>实现更好的动态终端编号 (@OpeOginni)</li><li>服务器选择对话框添加删除按钮 (@OpeOginni)</li></ul><h3 id="社区贡献-15-位贡献者" tabindex="-1">社区贡献（15 位贡献者） <a class="header-anchor" href="#社区贡献-15-位贡献者" aria-label="Permalink to “社区贡献（15 位贡献者）”">​</a></h3><p>@kynnyhsap, @OpeOginni, @jkoelker, @paoloricciuti, @jerome-benoit, @darshkpatel, @Adam8234, @roerohan, @malhashemi, @pschiel, @lengmodkx, @LeonMueller-OneAndOnly, @Eric-Guo, @ShoeBoom, @Brendonovich</p></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const g=t(o,[["render",d]]);export{m as __pageData,g as default};
